import { createDefaultBackendEnvironmentManager } from "./backendEnvironment.ts";

const platformDescriptor = Object.getOwnPropertyDescriptor(process, "platform");

function setPlatform(platform: NodeJS.Platform): void {
  Object.defineProperty(process, "platform", {
    configurable: true,
    value: platform,
  });
}

describe("backendEnvironment", () => {
  beforeEach(() => {
    localTargetInstances.length = 0;
    wslTargetInstances.length = 0;
    extractWslDistroFromPathMock.mockReset();
    getDefaultWslDistroMock.mockReset();
    isNodeAvailableInWslMock.mockReset();
    isWslAvailableMock.mockReset();
    isWslPathMock.mockReset();
    listWslDistrosMock.mockReset();
    prepareWslServerBundleMock.mockReset();
    setPlatform("win32");
  });

  afterEach(() => {
    if (platformDescriptor) {
      Object.defineProperty(process, "platform", platformDescriptor);
    }
  });

  it("creates isolated base directories for local and per-distro WSL environments", () => {
    isWslAvailableMock.mockReturnValue(true);
    listWslDistrosMock.mockReturnValue([
      { name: "Ubuntu-24.04", isDefault: true },
      { name: "Debian", isDefault: false },
    ]);
    isNodeAvailableInWslMock.mockReturnValue(true);
    getDefaultWslDistroMock.mockReturnValue("Ubuntu-24.04");
    prepareWslServerBundleMock.mockReturnValue({
      hostPath: "C:\\bundle",
      fingerprint: "bundle-fingerprint",
    });
    isWslPathMock.mockImplementation((folderPath: string) => folderPath.startsWith("\\\\wsl"));
    extractWslDistroFromPathMock.mockReturnValue("Debian");

    const manager = createDefaultBackendEnvironmentManager({
      rootBaseDir: "C:\\Users\\test\\.t3",
      appRoot: "D:\\Development\\TesseraCode\\t3code",
    });

    expect(manager.primaryEnvironment.key).toBe("wsl:Ubuntu-24.04");
    expect(manager.listEnvironments()).toEqual([
      expect.objectContaining({
        key: "local",
        baseDir: "C:\\Users\\test\\.t3",
      }),
      expect.objectContaining({
        key: "wsl:Ubuntu-24.04",
        baseDir: "C:\\Users\\test\\.t3\\environments\\wsl\\ubuntu-24-04",
      }),
      expect.objectContaining({
        key: "wsl:Debian",
        baseDir: "C:\\Users\\test\\.t3\\environments\\wsl\\debian",
      }),
    ]);
    expect(manager.resolveEnvironmentForPath("C:\\code").key).toBe("local");
    expect(manager.resolveEnvironmentForPath("\\\\wsl.localhost\\Debian\\home\\test").key).toBe(
      "wsl:Debian",
    );
    expect(wslTargetInstances).toEqual([
      expect.objectContaining({
        distro: "Ubuntu-24.04",
        installSourceRoot: "C:\\bundle",
        installFingerprint: "bundle-fingerprint",
      }),
      expect.objectContaining({
        distro: "Debian",
        installSourceRoot: "C:\\bundle",
        installFingerprint: "bundle-fingerprint",
      }),
    ]);
  });

  it("falls back to the local environment when WSL environments are unavailable", () => {
    isWslAvailableMock.mockReturnValue(false);
    getDefaultWslDistroMock.mockReturnValue(undefined);
    isWslPathMock.mockReturnValue(false);

    const manager = createDefaultBackendEnvironmentManager({
      rootBaseDir: "C:\\Users\\test\\.t3",
      appRoot: "D:\\Development\\TesseraCode\\t3code",
    });

    expect(manager.primaryEnvironment.key).toBe("local");
    expect(manager.listEnvironments()).toHaveLength(1);
    expect(manager.resolveEnvironmentForPath("\\\\wsl.localhost\\Ubuntu\\home\\test").key).toBe(
      "local",
    );
  });
});

import * as OS from "node:os";
import * as Path from "node:path";

import { LocalBackendTarget, type BackendTarget } from "./backendTarget.ts";
import {
  extractWslDistroFromPath,
  getDefaultWslDistro,
  isNodeAvailableInWsl,
  isWslAvailable,
  isWslPath,
  listWslDistros,
  WslBackendTarget,
} from "./wslBackendTarget.ts";
import { prepareWslServerBundle } from "./wslServerBundle.ts";

export interface ManagedBackendEnvironment {
  readonly key: string;
  readonly displayLabel: string;
  readonly kind: BackendTarget["type"];
  readonly target: BackendTarget;
  readonly baseDir: string;
}

export interface BackendEnvironmentManager {
  readonly primaryEnvironment: ManagedBackendEnvironment;
  listEnvironments(): readonly ManagedBackendEnvironment[];
  getEnvironment(key: string): ManagedBackendEnvironment | undefined;
  resolveEnvironmentForPath(folderPath: string): ManagedBackendEnvironment;
}

interface CreateDefaultBackendEnvironmentManagerOptions {
  readonly rootBaseDir: string;
  readonly appRoot: string;
}

function environmentPathFragment(value: string): string {
  const normalized = value
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
  return normalized.length > 0 ? normalized : "default";
}

function makeLocalEnvironment(rootBaseDir: string): ManagedBackendEnvironment {
  const target = new LocalBackendTarget();
  return {
    key: "local",
    displayLabel: target.displayLabel,
    kind: target.type,
    target,
    baseDir: rootBaseDir,
  };
}

function makeWslEnvironment(
  rootBaseDir: string,
  distro: string,
  installSourceRoot: string,
  installFingerprint: string,
): ManagedBackendEnvironment {
  const target = new WslBackendTarget({
    distro,
    installSourceRoot,
    installFingerprint,
  });
  return {
    key: `wsl:${distro}`,
    displayLabel: target.displayLabel,
    kind: target.type,
    target,
    baseDir: Path.join(rootBaseDir, "environments", "wsl", environmentPathFragment(distro)),
  };
}

export function createDefaultBackendEnvironmentManager(
  options: CreateDefaultBackendEnvironmentManagerOptions,
): BackendEnvironmentManager {
  const localEnvironment = makeLocalEnvironment(options.rootBaseDir);

  const wslEnvironments =
    process.platform === "win32" && isWslAvailable()
      ? (() => {
          const bundle = prepareWslServerBundle({
            appRoot: options.appRoot,
            cacheRoot: Path.join(OS.homedir(), ".t3", "wsl-server-bundles"),
          });
          if (!bundle) {
            return [];
          }

          return listWslDistros()
            .filter((distro) => isNodeAvailableInWsl(distro.name))
            .map((distro) =>
              makeWslEnvironment(
                options.rootBaseDir,
                distro.name,
                bundle.hostPath,
                bundle.fingerprint,
              ),
            );
        })()
      : [];

  const allEnvironments = [localEnvironment, ...wslEnvironments];
  const byKey = new Map(allEnvironments.map((environment) => [environment.key, environment]));
  const defaultDistro = getDefaultWslDistro();
  const primaryEnvironment =
    (defaultDistro ? byKey.get(`wsl:${defaultDistro}`) : undefined) ?? localEnvironment;

  return {
    primaryEnvironment,
    listEnvironments(): readonly ManagedBackendEnvironment[] {
      return allEnvironments;
    },
    getEnvironment(key: string): ManagedBackendEnvironment | undefined {
      return byKey.get(key);
    },
    resolveEnvironmentForPath(folderPath: string): ManagedBackendEnvironment {
      if (!isWslPath(folderPath)) {
        return localEnvironment;
      }

      const distro = extractWslDistroFromPath(folderPath);
      if (!distro) {
        return localEnvironment;
      }

      return byKey.get(`wsl:${distro}`) ?? localEnvironment;
    },
  };
}

import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";

const { execFileSyncMock, spawnMock } = vi.hoisted(() => ({
  execFileSyncMock: vi.fn(),
  spawnMock: vi.fn(),
}));

vi.mock("node:child_process", () => ({
  execFileSync: execFileSyncMock,
  spawn: spawnMock,
}));

import {
  canReachNpmRegistryInWsl,
  installServerInWsl,
  listWslDistros,
  WslBackendTarget,
} from "./wslBackendTarget.ts";

const platformDescriptor = Object.getOwnPropertyDescriptor(process, "platform");

function setPlatform(platform: NodeJS.Platform): void {
  Object.defineProperty(process, "platform", {
    configurable: true,
    value: platform,
  });
}

describe("wslBackendTarget", () => {
  beforeEach(() => {
    execFileSyncMock.mockReset();
    spawnMock.mockReset();
    setPlatform("win32");
  });

  afterEach(() => {
    if (platformDescriptor) {
      Object.defineProperty(process, "platform", platformDescriptor);
    }
  });

  it("decodes UTF-16LE distro names from wsl.exe", () => {
    execFileSyncMock.mockReturnValue(Buffer.from("\uFEFFUbuntu-24.04\nDebian\n", "utf16le"));

    expect(listWslDistros()).toEqual([
      { name: "Ubuntu-24.04", isDefault: true },
      { name: "Debian", isDefault: false },
    ]);
    expect(execFileSyncMock).toHaveBeenCalledWith(
      "wsl.exe",
      ["--list", "--quiet"],
      expect.objectContaining({ timeout: 10000 }),
    );
  });

  it("installs the staged server bundle inside WSL using npm instead of copying Windows node_modules", () => {
    execFileSyncMock
      .mockReturnValueOnce(Buffer.from(""))
      .mockReturnValueOnce("/mnt/c/Users/test/bundle\n")
      .mockReturnValueOnce(Buffer.from(""))
      .mockReturnValueOnce(Buffer.from(""));

    const installed = installServerInWsl("C:\\Users\\test\\bundle", "Ubuntu-24.04");

    expect(installed).toBe(true);
    expect(execFileSyncMock).toHaveBeenNthCalledWith(
      1,
      "wsl.exe",
      [
        "-d",
        "Ubuntu-24.04",
        "--exec",
        "bash",
        "-c",
        expect.stringContaining("npm ping --loglevel error >/dev/null"),
      ],
      expect.objectContaining({ timeout: 20000 }),
    );
    expect(execFileSyncMock).toHaveBeenNthCalledWith(
      2,
      "wsl.exe",
      ["-d", "Ubuntu-24.04", "--exec", "wslpath", "-u", "C:\\Users\\test\\bundle"],
      expect.objectContaining({ encoding: "utf-8", timeout: 5000 }),
    );

    const installArgs = execFileSyncMock.mock.calls[2]?.[1] as string[];
    const installScript = installArgs[5];

    expect(installArgs).toEqual([
      "-d",
      "Ubuntu-24.04",
      "--exec",
      "bash",
      "-c",
      expect.any(String),
      "bash",
      "/mnt/c/Users/test/bundle",
    ]);
    expect(installScript).toContain(
      "npm install --omit=dev --no-package-lock --no-audit --no-fund",
    );
    expect(installScript).not.toContain("node_modules");
  });

  it("fails fast when the npm registry is unreachable from WSL", () => {
    execFileSyncMock.mockImplementation(() => {
      throw new Error("connect ETIMEDOUT");
    });

    expect(canReachNpmRegistryInWsl("Ubuntu-24.04")).toBe(false);
    expect(installServerInWsl("C:\\Users\\test\\bundle", "Ubuntu-24.04")).toBe(false);
    expect(execFileSyncMock).toHaveBeenCalledTimes(2);
  });

  it("reinstalls the bundle when the installed fingerprint is stale", () => {
    execFileSyncMock.mockImplementation((file: string, args: string[]) => {
      if (file !== "wsl.exe") {
        throw new Error(`Unexpected command: ${file}`);
      }

      const command = args.join(" ");
      if (command.includes("--status")) {
        return Buffer.from("");
      }
      if (command.includes("node --version")) {
        return Buffer.from("v24.13.1\n");
      }
      if (command.includes("npm ping --loglevel error >/dev/null")) {
        return Buffer.from("");
      }
      if (command.includes('test -f "$HOME/.t3/server/apps/server/dist/bin.mjs"')) {
        return Buffer.from("");
      }
      if (command.includes('cat "$HOME/.t3/server/.wsl-bundle-fingerprint"')) {
        return "stale-fingerprint\n";
      }
      if (command.includes("wslpath -u C:\\Users\\test\\bundle")) {
        return "/mnt/c/Users/test/bundle\n";
      }
      if (command.includes("npm install --omit=dev --no-package-lock --no-audit --no-fund")) {
        return Buffer.from("");
      }

      throw new Error(`Unexpected wsl.exe args: ${command}`);
    });

    const target = new WslBackendTarget({
      distro: "Ubuntu-24.04",
      installSourceRoot: "C:\\Users\\test\\bundle",
      installFingerprint: "expected-fingerprint",
    });

    expect(target.ensureReady()).toBe(true);
    expect(
      execFileSyncMock.mock.calls.some(
        ([file, args]) =>
          file === "wsl.exe" &&
          Array.isArray(args) &&
          args.some((value) => typeof value === "string" && value.includes("npm install")),
      ),
    ).toBe(true);
  });
});

import fs from "node:fs";
import os from "node:os";
import path from "node:path";

import { describe, expect, it } from "vitest";

import { createWslServerRuntimePackageJson, prepareWslServerBundle } from "./wslServerBundle.ts";

describe("wslServerBundle", () => {
  it("creates a runtime package manifest with resolved dependency versions", () => {
    const runtimePackageJson = createWslServerRuntimePackageJson();

    expect(runtimePackageJson.name).toBe("t3");
    expect(runtimePackageJson.dependencies.effect).not.toContain("catalog:");
    expect(runtimePackageJson.dependencies["@effect/platform-node"]).not.toContain("catalog:");
    expect(Object.values(runtimePackageJson.dependencies)).not.toContain("workspace:*");
  });

  it("stages a portable server bundle and fingerprints dist changes", () => {
    const appRoot = fs.mkdtempSync(path.join(os.tmpdir(), "t3-wsl-bundle-app-"));
    const cacheRoot = fs.mkdtempSync(path.join(os.tmpdir(), "t3-wsl-bundle-cache-"));
    const sourceDistDir = path.join(appRoot, "apps", "server", "dist", "nested");

    try {
      fs.mkdirSync(sourceDistDir, { recursive: true });
      fs.writeFileSync(path.join(appRoot, "apps", "server", "dist", "bin.mjs"), "export {}\n");
      fs.writeFileSync(path.join(sourceDistDir, "worker.mjs"), "export const worker = true\n");

      const first = prepareWslServerBundle({ appRoot, cacheRoot });

      expect(first).toBeDefined();
      expect(fs.existsSync(path.join(first!.hostPath, "apps", "server", "dist", "bin.mjs"))).toBe(
        true,
      );
      expect(fs.existsSync(path.join(first!.hostPath, "apps", "server", "package.json"))).toBe(
        true,
      );

      const initialFingerprint = first!.fingerprint;
      fs.writeFileSync(
        path.join(appRoot, "apps", "server", "dist", "bin.mjs"),
        "export const ready = true\n",
      );

      const second = prepareWslServerBundle({ appRoot, cacheRoot });

      expect(second).toBeDefined();
      expect(second!.fingerprint).not.toBe(initialFingerprint);
      expect(second!.hostPath).not.toBe(first!.hostPath);
    } finally {
      fs.rmSync(appRoot, { recursive: true, force: true });
      fs.rmSync(cacheRoot, { recursive: true, force: true });
    }
  });
});

import * as Crypto from "node:crypto";
import * as FS from "node:fs";
import * as OS from "node:os";
import * as Path from "node:path";

import rootPackageJson from "../../../package.json" with { type: "json" };
import serverPackageJson from "../../server/package.json" with { type: "json" };

interface WslServerRuntimePackageJson {
  readonly name: string;
  readonly version: string;
  readonly repository: {
    readonly type: string;
    readonly url: string;
    readonly directory: string;
  };
  readonly bin: Record<string, string>;
  readonly type: string;
  readonly engines: Record<string, string>;
  readonly files: string[];
  readonly dependencies: Record<string, string>;
  readonly overrides: Record<string, string>;
}

export interface PreparedWslServerBundle {
  readonly hostPath: string;
  readonly fingerprint: string;
}

function resolveCatalogDependencies(
  dependencies: Record<string, string>,
  catalog: Record<string, string>,
  label: string,
): Record<string, string> {
  return Object.fromEntries(
    Object.entries(dependencies).map(([name, spec]) => {
      if (typeof spec !== "string" || !spec.startsWith("catalog:")) {
        return [name, spec];
      }

      const catalogKey = spec.slice("catalog:".length).trim();
      const lookupKey = catalogKey.length > 0 ? catalogKey : name;
      const resolved = catalog[lookupKey];

      if (typeof resolved !== "string" || resolved.length === 0) {
        throw new Error(
          `Unable to resolve '${spec}' for ${label} dependency '${name}'. Expected key '${lookupKey}' in root workspace catalog.`,
        );
      }

      return [name, resolved];
    }),
  );
}

export function createWslServerRuntimePackageJson(): WslServerRuntimePackageJson {
  return {
    name: serverPackageJson.name,
    version: serverPackageJson.version,
    repository: serverPackageJson.repository,
    bin: serverPackageJson.bin,
    type: serverPackageJson.type,
    engines: serverPackageJson.engines,
    files: serverPackageJson.files,
    dependencies: resolveCatalogDependencies(
      serverPackageJson.dependencies,
      rootPackageJson.workspaces.catalog,
      "apps/server",
    ),
    overrides: resolveCatalogDependencies(
      rootPackageJson.overrides,
      rootPackageJson.workspaces.catalog,
      "apps/server",
    ),
  };
}

function updateHashFromDirectory(hash: Crypto.Hash, directory: string, relativeRoot = ""): void {
  const entries = FS.readdirSync(directory, { withFileTypes: true }).toSorted((left, right) =>
    left.name.localeCompare(right.name),
  );

  for (const entry of entries) {
    const absolutePath = Path.join(directory, entry.name);
    const relativePath = relativeRoot.length > 0 ? `${relativeRoot}/${entry.name}` : entry.name;
    hash.update(relativePath);

    if (entry.isDirectory()) {
      hash.update("dir");
      updateHashFromDirectory(hash, absolutePath, relativePath);
      continue;
    }

    if (entry.isFile()) {
      hash.update("file");
      hash.update(FS.readFileSync(absolutePath));
    }
  }
}

function computeBundleFingerprint(sourceDistDir: string, runtimePackageJson: string): string {
  const hash = Crypto.createHash("sha256");
  hash.update(runtimePackageJson);
  updateHashFromDirectory(hash, sourceDistDir);
  return hash.digest("hex").slice(0, 16);
}

export function prepareWslServerBundle(input: {
  readonly appRoot: string;
  readonly cacheRoot?: string;
}): PreparedWslServerBundle | undefined {
  const sourceDistDir = Path.join(input.appRoot, "apps/server/dist");
  const sourceEntry = Path.join(sourceDistDir, "bin.mjs");
  if (!FS.existsSync(sourceEntry)) {
    return undefined;
  }

  const runtimePackageJson = `${JSON.stringify(createWslServerRuntimePackageJson(), null, 2)}\n`;
  const fingerprint = computeBundleFingerprint(sourceDistDir, runtimePackageJson);
  const cacheRoot = input.cacheRoot ?? Path.join(OS.homedir(), ".t3", "wsl-server-bundles");
  const bundleDir = Path.join(cacheRoot, fingerprint);
  const fingerprintFile = Path.join(bundleDir, ".wsl-bundle-fingerprint");

  if (!FS.existsSync(fingerprintFile)) {
    FS.rmSync(bundleDir, { recursive: true, force: true });
    FS.mkdirSync(Path.join(bundleDir, "apps/server"), { recursive: true });
    FS.cpSync(sourceDistDir, Path.join(bundleDir, "apps/server/dist"), { recursive: true });
    FS.writeFileSync(Path.join(bundleDir, "apps/server/package.json"), runtimePackageJson);
    FS.writeFileSync(fingerprintFile, `${fingerprint}\n`);
  }

  return {
    hostPath: bundleDir,
    fingerprint,
  };
}

import { scopeThreadRef } from "@t3tools/client-runtime";
import { EnvironmentId, ProjectId, ThreadId } from "@t3tools/contracts";
import { describe, expect, it } from "vitest";

import { isReusableDraftForProjectRef } from "./projectDrafts";

const projectRef = {
  environmentId: EnvironmentId.make("environment-local"),
  projectId: ProjectId.make("project-alpha"),
} as const;

describe("isReusableDraftForProjectRef", () => {
  it("accepts a draft already bound to the same physical project", () => {
    expect(
      isReusableDraftForProjectRef(projectRef, {
        environmentId: projectRef.environmentId,
        projectId: projectRef.projectId,
      }),
    ).toBe(true);
  });

  it("rejects a draft from another environment for the same logical repo", () => {
    expect(
      isReusableDraftForProjectRef(projectRef, {
        environmentId: EnvironmentId.make("environment-wsl"),
        projectId: projectRef.projectId,
      }),
    ).toBe(false);
  });

  it("rejects a draft from another physical project in the same environment", () => {
    expect(
      isReusableDraftForProjectRef(projectRef, {
        environmentId: projectRef.environmentId,
        projectId: ProjectId.make("project-beta"),
      }),
    ).toBe(false);
  });

  it("rejects a draft that is already being promoted", () => {
    expect(
      isReusableDraftForProjectRef(projectRef, {
        environmentId: projectRef.environmentId,
        projectId: projectRef.projectId,
        promotedTo: scopeThreadRef(projectRef.environmentId, ThreadId.make("thread-1")),
      }),
    ).toBe(false);
  });
});

import type { ScopedProjectRef, ScopedThreadRef } from "@t3tools/contracts";

interface ProjectScopedDraftLike {
  readonly environmentId: ScopedProjectRef["environmentId"];
  readonly projectId: ScopedProjectRef["projectId"];
  readonly promotedTo?: ScopedThreadRef | null;
}

export function isReusableDraftForProjectRef(
  projectRef: ScopedProjectRef,
  draft: ProjectScopedDraftLike | null | undefined,
): boolean {
  if (!draft || draft.promotedTo != null) {
    return false;
  }

  return (
    draft.environmentId === projectRef.environmentId && draft.projectId === projectRef.projectId
  );
}

